sqrt_avg

sqrt_avg &lt;- function(x){
  begin = 0
  end = x
  repeat{
    mid &lt;- (begin + end)/2
    err &lt;- x - mid * mid
    if(abs(err) &lt; 1e-8) break
    if(err &gt; 0) begin &lt;- mid
    else end &lt;- mid
  }
  mid
}
