sqrt_heron

sqrt_heron &lt;- function(x){
  x0 &lt;- 1
  repeat{
    x_new &lt;- (x0 + x/x0)/2
    if(abs(x_new - x0) &lt; 1e-8) break
    x0 &lt;- x_new
  }
  x0
}
